class Solution:
    def countNumbers(self, l: str, r: str, b: int) -> int:
        MOD = 10**9 + 7
        def count(n):
            res = 0
            for i in range(len(n)):
                for j in range(int(n[i]), b):
                    res += b**(len(n)-i-1)
            return res
        l, r = int(l, b), int(r, b)
        res = 0
        for i in range(l, r+1):
            s = ''
            while i:
                s = str(i%b) + s
                i //= b
            flag = True
            for j in range(len(s)-1):
                if s[j] > s[j+1]:
                    flag = False
                    break
            if flag:
                res += 1
        return res % MOD
